body.script:
function openModal(id) { const modal = document.getElementById(id); if (modal) { modal.classList.add('active'); if (id === 'announcement-modal') { userSettings.announcementRead = true; saveState(); const badge = document.getElementById('bell-badge'); if (badge) badge.classList.remove('active'); } } }
function closeModals() { document.querySelectorAll('.modal-overlay').forEach(m => m.classList.remove('active')); }
function handleBackdropClick(e) { if (e.target.classList.contains('modal-overlay')) { closeModals(); } }
window.addEventListener("load", function () { if (!localStorage.getItem("hasSeenAlert")) {
alert("UPDATE: More themes. . Bunch of patches. Terms of service. PWA app");
localStorage.setItem("hasSeenAlert", "true"); } }); // --- AUTOMATIC INTERSTELLAR-STYLE ABOUT:BLANK --- (function autoLaunchAB() { // 1. Check if we are already safely hidden in an iframe OR inside about:blank if (window !== window.top || window.location.protocol === "about:") return;
// 2. Fetch settings let userSettings = JSON.parse(localStorage.getItem('edulearn_settings')) || { abEnabled: true };
// 3. Check if AB is enabled if (!userSettings.abEnabled) return;
function spawnStealthWindow(win) { win.document.title = userSettings.cloakTitle || "EduLearn"; if (userSettings.cloakIcon) { let link = win.document.createElement('link'); link.rel = 'icon'; link.href = userSettings.cloakIcon; win.document.head.appendChild(link); } win.document.body.style.margin = "0"; let iframe = win.document.createElement("iframe"); iframe.style.border = "none"; iframe.style.width = "100vw"; iframe.style.height = "100vh"; iframe.src = window.location.href; win.document.body.appendChild(iframe);
// Random safe redirect list const panicLinks = [ "https://classroom.google.com", "https://clever.com", "https://quizlet.com", "https://www.iready.com", "https://infinitecampus.com", "https://docs.google.com", "https://drive.google.com", "https://slides.google.com", "https://mail.google.com", "https://calendar.google.com", "https://google.com", "https://wikipedia.org", "https://blooket.com", "https://kahoot.com", "https://scratch.mit.edu", "https://nasa.gov", "https://mit.edu", "https://youtube.com", "https://www.khanacademy.org/", "https://ixl.com", "https://www.typing.com", "https://www.duolingo.com", "https://brainpop.com", "https://www.nationalgeographic.com/", "https://desmos.com/calculator",
];
// Pick random link const randomLink = panicLinks[Math.floor(Math.random() * panicLinks.length)];
// Push original tab away window.location.replace(randomLink); }
// 4. Try opening instantly function tryOpenAboutBlank() { const win = window.open('about:blank', '_blank'); if (win) { spawnStealthWindow(win); return true; } return false; }
function scheduleTry(delay) { setTimeout(() => { if (!tryOpenAboutBlank()) { setTimeout(tryOpenAboutBlank, 700); } }, delay); }
if (!tryOpenAboutBlank()) { window.addEventListener('load', () => scheduleTry(100)); scheduleTry(50);
alert("PLEASE TAKE THE TIME AND READ THIS: If you do not have popups enabled, PLEASE enable popups to HIDE this page from SECURLY Classroom, and your HISTORY! POPUPS ARE HIGHLY RECOMMENDED and can be ENABLED from the TOP RIGHT corner of your screen, next to the bookmarks star theres a small icon that has a DIAGNOL SLASH over it! SET THAT TO ALWAYS ALLOW~"); document.addEventListener('click', function fallbackClick(e) { if (e.target.closest('.switch')) return;
if (tryOpenAboutBlank()) { document.removeEventListener('click', fallbackClick); } }); } })();
