function updateQuote() { const quoteEl = document.getElementById('quote-display'); quoteEl.textContent = `"${quotes[Math.floor(Math.random() * quotes.length)]}"`; } updateQuote();
async function openWithScramjet(rawInput) { const cleanedInput = (rawInput || '').trim(); if (!cleanedInput) return;
const targetUrl = search(cleanedInput, "https://duckduckgo.com/?q=%s"); localStorage.setItem('edulearn_home_launch', targetUrl); window.location.href = `/algebra.html?q=${encodeURIComponent(targetUrl)}`; }
document.getElementById('home-search-form').addEventListener('submit', async (event) => { event.preventDefault(); const input = document.getElementById('home-search-input'); await openWithScramjet(input.value); });
document.querySelectorAll('.quickapp-btn').forEach((button) => { button.addEventListener('click', async () => { if (button.dataset.action === 'games') { window.location.href = '/g/'; return; }
const quickUrl = button.dataset.url; if (quickUrl) { await openWithScramjet(quickUrl); } }); });
// --- ONLINE USERS TRACKER --- (function initOnlineCounter() { // 1. Get or create a unique ID for this browser let userId = localStorage.getItem('edulearn_uid'); if (!userId) { userId = Math.random().toString(36).substring(2, 15); localStorage.setItem('edulearn_uid', userId); }
// 2. Ping your Vercel API async function pingOnline() { const countSpan = document.getElementById('online-count'); try { const response = await fetch(`/api/online?id=${userId}`); if (!response.ok) { if (countSpan) countSpan.innerText = 'offline (static build)'; return; }
const data = await response.json(); if (countSpan) { countSpan.innerText = String(data.online ?? 1); } } catch (err) { console.error("Failed to ping online API:", err); if (countSpan) countSpan.innerText = 'offline'; } }
// 3. Ping immediately, then every 30 seconds pingOnline(); setInterval(pingOnline, 30000); })();
// --- SETTINGS LOGIC --- const DEFAULT_SETTINGS = { panicKey: 'Escape', panicUrl: 'https://classroom.google.com', cloakTitle: 'EduLearn — Academic Courses & Resources', cloakIcon: '', announcementRead: false, abEnabled: true, particlesEnabled: true, closePreventionEnabled: false, leaveSiteEnabled: false, theme: 'midnight', customTheme: { bg: '#1e1e2e', bgAlt: '#181825', text: '#cdd6f4', accent: '#89b4fa' } };
let userSettings = { ...DEFAULT_SETTINGS, ...(JSON.parse(localStorage.getItem('edulearn_settings')) || {}), customTheme: { ...DEFAULT_SETTINGS.customTheme, ...((JSON.parse(localStorage.getItem('edulearn_settings')) || {}).customTheme || {}) } };
function saveState() { localStorage.setItem('edulearn_settings', JSON.stringify(userSettings)); }
function initSettings() { document.getElementById('panic-key').value = userSettings.panicKey || 'Escape'; document.getElementById('panic-url').value = userSettings.panicUrl || 'https://classroom.google.com'; document.getElementById('cloak-title').value = userSettings.cloakTitle || 'EduLearn'; document.getElementById('cloak-icon').value = userSettings.cloakIcon || '';
// Toggle syncs with actual state (defaults to checked if null) document.getElementById('ab-toggle').checked = userSettings.abEnabled !== false; document.getElementById('particles-toggle').checked = userSettings.particlesEnabled !== false; document.getElementById('close-prevention-toggle').checked = userSettings.closePreventionEnabled === true; document.getElementById('leave-site-toggle').checked = userSettings.leaveSiteEnabled === true; document.getElementById('leave-site-row').style.display = userSettings.closePreventionEnabled ? 'flex' : 'none'; updateLeaveProtection();
document.getElementById('theme-select').value = userSettings.theme || 'default'; document.getElementById('custom-bg').value = userSettings.customTheme?.bg || DEFAULT_SETTINGS.customTheme.bg; document.getElementById('custom-bg-alt').value = userSettings.customTheme?.bgAlt || DEFAULT_SETTINGS.customTheme.bgAlt; document.getElementById('custom-text').value = userSettings.customTheme?.text || DEFAULT_SETTINGS.customTheme.text; document.getElementById('custom-accent').value = userSettings.customTheme?.accent || DEFAULT_SETTINGS.customTheme.accent;
const torEnabled = localStorage.getItem('tor_enabled') === 'true'; const torToggle = document.getElementById('tor-toggle'); if (torToggle) torToggle.checked = torEnabled;
const adblockEnabled = localStorage.getItem('adblock_enabled') === 'true'; const adblockToggle = document.getElementById('adblock-toggle'); if (adblockToggle) adblockToggle.checked = adblockEnabled;
// Apply theme (including custom if selected) applyTheme(userSettings.theme || 'default');
// Apply Cloak immediately document.getElementById('page-title').innerText = userSettings.cloakTitle || 'EduLearn'; if (userSettings.cloakIcon) { document.getElementById('dynamic-favicon').href = userSettings.cloakIcon; }
// Check announcements if (!userSettings.announcementRead) { const badge = document.getElementById('bell-badge'); if (badge) badge.classList.add('active'); } }
function savePanic() { userSettings.panicKey = document.getElementById('panic-key').value || 'Escape'; userSettings.panicUrl = document.getElementById('panic-url').value || 'https://classroom.google.com'; saveState(); alert("Panic button saved successfully!"); }
function toggleClosePrevention() { const enabled = document.getElementById('close-prevention-toggle').checked; userSettings.closePreventionEnabled = enabled; if (!enabled) { userSettings.leaveSiteEnabled = false; const leaveToggle = document.getElementById('leave-site-toggle'); if (leaveToggle) leaveToggle.checked = false; } document.getElementById('leave-site-row').style.display = enabled ? 'flex' : 'none'; saveState(); updateLeaveProtection(); }
function toggleLeaveSite() { userSettings.leaveSiteEnabled = document.getElementById('leave-site-toggle').checked; saveState(); updateLeaveProtection(); }
function updateLeaveProtection() { window.onbeforeunload = null; if (userSettings.closePreventionEnabled && !userSettings.leaveSiteEnabled) { window.onbeforeunload = () => "Are you sure you want to leave EduLearn?"; } }
function saveCloak() { userSettings.cloakTitle = document.getElementById('cloak-title').value || 'EduLearn'; userSettings.cloakIcon = document.getElementById('cloak-icon').value || ''; saveState(); initSettings(); // Reload title/favicon }
const TAB_PRESETS = { classroom: { title: 'Classes', icon: 'https://ssl.gstatic.com/classroom/favicon.png' }, docs: { title: 'Google Docs', icon: 'https://ssl.gstatic.com/docs/documents/images/kix-favicon7.ico' }, drive: { title: 'My Drive - Google Drive', icon: 'https://ssl.gstatic.com/docs/doclist/images/drive_2022q3_32dp.png' }, gmail: { title: 'Gmail', icon: 'https://ssl.gstatic.com/ui/v1/icons/mail/images/2/favicon.ico' }, calendar: { title: 'Google Calendar', icon: 'https://www.gstatic.com/calendar/images/favicon_v2014_31.ico' }, canvas: { title: 'Dashboard', icon: 'https://du11hjcvx0uqb.cloudfront.net/dist/images/favicon-e10d657a73.ico' }, schoology: { title: 'Home | Schoology', icon: 'https://asset-cdn.schoology.com/sites/all/themes/schoology_theme/favicon.ico' }, clever: { title: 'Clever | Portal', icon: 'https://assets.clever.com/launchpad/f45a164/favicon.ico' }, kahoot: { title: 'Kahoot!', icon: 'https://kahoot.com/favicon.ico' }, quizlet: { title: 'Flashcards, learning tools and textbook solutions | Quizlet', icon: 'https://quizlet.com/favicon.ico' }, desmos: { title: 'Desmos | Scientific Calculator', icon: 'https://www.desmos.com/favicon.ico' }, zoom: { title: 'Zoom', icon: 'https://st1.zoom.us/zoom.ico' }, teams: { title: 'Microsoft Teams', icon: 'https://statics.teams.cdn.office.net/evergreen-assets/apps/teams_dev.ico' }, outlook: { title: 'Outlook', icon: 'https://res-h3.public.cdn.office.net/assets/mail/favicon-1.ico' } };
function toggleTor() { const enabled = document.getElementById('tor-toggle').checked; localStorage.setItem('tor_enabled', enabled); }
function toggleAdblock() { const enabled = document.getElementById('adblock-toggle').checked; localStorage.setItem('adblock_enabled', enabled); }
function applyTabPreset() { const selectedPreset = document.getElementById('cloak-preset').value; if (!selectedPreset || !TAB_PRESETS[selectedPreset]) return; const preset = TAB_PRESETS[selectedPreset]; document.getElementById('cloak-title').value = preset.title; document.getElementById('cloak-icon').value = preset.icon; saveCloak(); }
const TEMPLATED_THEMES = { default: { bg: '#1e1e2e', bgAlt: '#181825', text: '#cdd6f4', accent: '#89b4fa', panel: 'rgba(30, 30, 46, 0.92)', border: 'rgba(137, 180, 250, 0.25)', shadow: 'rgba(0,0,0,0.35)' }, macchiato: { bg: '#24273a', bgAlt: '#1f2233', text: '#cad3f5', accent: '#8aadf4', panel: 'rgba(36, 39, 58, 0.92)', border: 'rgba(138, 173, 244, 0.25)', shadow: 'rgba(0,0,0,0.35)' }, latte: { bg: '#eff1f5', bgAlt: '#e6e9ef', text: '#4c4f69', accent: '#1e66f5', panel: 'rgba(230, 233, 239, 0.94)', border: 'rgba(30, 102, 245, 0.2)', shadow: 'rgba(76, 79, 105, 0.2)' }, cosmos: { bg: '#120936', bgAlt: '#1d1d3c', text: '#f7f2ff', accent: '#b488ff', panel: 'rgba(34, 21, 54, 0.9)', border: 'rgba(140,97,229,0.25)', shadow: 'rgba(19, 7, 49, 0.6)' }, forest: { bg: '#0a1410', bgAlt: '#152e22', text: '#e6f7e8', accent: '#7ad29e', panel: 'rgba(10, 26, 16, 0.88)', border: 'rgba(90, 188, 135, 0.28)', shadow: 'rgba(2, 13, 8, 0.4)' }, sunset: { bg: '#2b0c07', bgAlt: '#4f2310', text: '#ffe8da', accent: '#ffb86c', panel: 'rgba(60, 25, 14, 0.9)', border: 'rgba(255,150,100,0.28)', shadow: 'rgba(35, 12, 6, 0.5)' }, matrix: { bg: '#041803', bgAlt: '#0b2b05', text: '#a3f8a4', accent: '#55ff5c', panel: 'rgba(2, 25, 8, 0.87)', border: 'rgba(80,230,90,0.25)', shadow: 'rgba(5, 17, 5, 0.45)' }, sakura: { bg: '#feeaf1', bgAlt: '#fddde6', text: '#d84b7a', accent: '#ff8fab', panel: 'rgba(253, 221, 230, 0.92)', border: 'rgba(255, 143, 171, 0.25)', shadow: 'rgba(216, 75, 122, 0.15)' }, pink: { bg: '#1a0b16', bgAlt: '#2d132c', text: '#ffc2d1', accent: '#ff5d8f', panel: 'rgba(45, 19, 44, 0.92)', border: 'rgba(255, 93, 143, 0.3)', shadow: 'rgba(0, 0, 0, 0.5)' }, ocean: { bg: '#0b132b', bgAlt: '#1c2541', text: '#edeff2', accent: '#5bc0be', panel: 'rgba(28, 37, 65, 0.92)', border: 'rgba(91, 192, 190, 0.3)', shadow: 'rgba(0, 0, 0, 0.5)' }, midnight: { bg: '#050505', bgAlt: '#121212', text: '#ffffff', accent: '#ffffff', panel: 'rgba(18, 18, 18, 0.92)', border: 'rgba(255, 255, 255, 0.2)', shadow: 'rgba(0, 0, 0, 0.8)' }, nord: { bg: '#2e3440', bgAlt: '#3b4252', text: '#eceff4', accent: '#88c0d0', panel: 'rgba(59, 66, 82, 0.92)', border: 'rgba(136, 192, 208, 0.25)', shadow: 'rgba(0, 0, 0, 0.4)' }, gruvbox: { bg: '#282828', bgAlt: '#3c3836', text: '#ebdbb2', accent: '#fe8019', panel: 'rgba(60, 56, 54, 0.92)', border: 'rgba(254, 128, 25, 0.25)', shadow: 'rgba(0, 0, 0, 0.5)' }, dracula: { bg: '#282a36', bgAlt: '#44475a', text: '#f8f8f2', accent: '#bd93f9', panel: 'rgba(68, 71, 90, 0.92)', border: 'rgba(189, 147, 249, 0.3)', shadow: 'rgba(0, 0, 0, 0.5)' }, cyberpunk: { bg: '#000000', bgAlt: '#1a1a1a', text: '#00ff00', accent: '#fdee00', panel: 'rgba(26, 26, 26, 0.95)', border: 'rgba(253, 238, 0, 0.4)', shadow: 'rgba(253, 238, 0, 0.1)' }, monokai: { bg: '#272822', bgAlt: '#3e3d32', text: '#f8f8f2', accent: '#a6e22e', panel: 'rgba(62, 61, 50, 0.92)', border: 'rgba(166, 226, 46, 0.3)', shadow: 'rgba(0, 0, 0, 0.5)' }, aura: { bg: '#15141b', bgAlt: '#1b1a23', text: '#edecee', accent: '#a277ff', panel: 'rgba(27, 26, 35, 0.92)', border: 'rgba(162, 119, 255, 0.3)', shadow: 'rgba(0, 0, 0, 0.6)' }, solarized: { bg: '#002b36', bgAlt: '#073642', text: '#839496', accent: '#268bd2', panel: 'rgba(7, 54, 66, 0.92)', border: 'rgba(38, 139, 210, 0.3)', shadow: 'rgba(0, 0, 0, 0.6)' }, crimson: { bg: '#1a0000', bgAlt: '#330000', text: '#ffcccc', accent: '#ff0000', panel: 'rgba(51, 0, 0, 0.92)', border: 'rgba(255, 0, 0, 0.3)', shadow: 'rgba(0, 0, 0, 0.8)' }, gold: { bg: '#0a0a0a', bgAlt: '#1a1a1a', text: '#f3e5ab', accent: '#ffd700', panel: 'rgba(26, 26, 26, 0.92)', border: 'rgba(255, 215, 0, 0.3)', shadow: 'rgba(255, 215, 0, 0.1)' } };
function setThemeVars(vars) { document.documentElement.style.setProperty('--bg', vars.bg); document.documentElement.style.setProperty('--bg-alt', vars.bgAlt); document.documentElement.style.setProperty('--text-main', vars.text); document.documentElement.style.setProperty('--text-muted', vars.muted || 'color-mix(in srgb, var(--text-main) 72%, transparent)'); document.documentElement.style.setProperty('--accent', vars.accent); document.documentElement.style.setProperty('--panel', vars.panel || 'rgba(30, 30, 46, 0.92)'); document.documentElement.style.setProperty('--border', vars.border || 'rgba(137,180,250,0.25)'); document.documentElement.style.setProperty('--shadow', vars.shadow || 'rgba(0,0,0,0.35)'); document.documentElement.style.setProperty('--bubble-highlight', vars.highlight || 'color-mix(in srgb, var(--accent) 38%, transparent)'); }
function applyTheme(themeName) { userSettings.theme = themeName; if (themeName === 'custom') { setThemeVars({ bg: userSettings.customTheme.bg, bgAlt: userSettings.customTheme.bgAlt, text: userSettings.customTheme.text, accent: userSettings.customTheme.accent, panel: userSettings.customTheme.bgAlt, border: 'color-mix(in srgb, var(--accent) 35%, transparent)', shadow: 'rgba(0,0,0,0.35)', highlight: 'color-mix(in srgb, var(--accent) 38%, transparent)' }); document.getElementById('custom-theme-row').style.display = 'flex'; } else { document.getElementById('custom-theme-row').style.display = 'none'; if (TEMPLATED_THEMES[themeName]) { setThemeVars(TEMPLATED_THEMES[themeName]); } else { setThemeVars(TEMPLATED_THEMES['default']); userSettings.theme = 'default'; } } saveState(); document.getElementById('theme-select').value = userSettings.theme; document.body.style.background = `linear-gradient(160deg, var(--bg), var(--bg-alt))`; }
function saveCustomTheme() { const bg = document.getElementById('custom-bg').value; const bgAlt = document.getElementById('custom-bg-alt').value; const text = document.getElementById('custom-text').value; const accent = document.getElementById('custom-accent').value; userSettings.customTheme = { bg, bgAlt, text, accent }; userSettings.theme = 'custom'; saveState(); applyTheme('custom'); alert('Custom theme saved!'); }
// Manual Toggle from settings menu function toggleAB() { let enabled = document.getElementById('ab-toggle').checked; userSettings.abEnabled = enabled; saveState();
if (enabled && window.top === window.self && window.location.protocol !== "about:") { let win = window.open('about:blank', '_blank'); if (win) { win.document.title = userSettings.cloakTitle || "EduLearn"; win.document.body.style.margin = "0"; let iframe = win.document.createElement("iframe"); iframe.style.border = "none"; iframe.style.width = "100vw"; iframe.style.height = "100vh"; iframe.src = window.location.href; win.document.body.appendChild(iframe); window.location.replace("https://classroom.google.com"); } } }
function toggleParticles() { const enabled = document.getElementById('particles-toggle').checked; userSettings.particlesEnabled = enabled; saveState();
// Auto-repair: If enabling, ensure the system is initialized and running if (enabled) { if (typeof initEdulearnParticles === 'function') { initEdulearnParticles(); } if (window.edulearnParticles) { window.edulearnParticles.start(); } } else { if (window.edulearnParticles) { window.edulearnParticles.stop(); } } }
// Theme selector events + init document.addEventListener('DOMContentLoaded', () => { const themeSelect = document.getElementById('theme-select'); if (themeSelect) { themeSelect.addEventListener('change', (e) => { const selected = e.target.value; if (selected === 'custom') { document.getElementById('custom-theme-row').style.display = 'flex'; } else { document.getElementById('custom-theme-row').style.display = 'none'; } applyTheme(selected);
// Update particles color on theme change const accent = getComputedStyle(document.documentElement).getPropertyValue('--accent').trim(); if (window.edulearnParticles && accent) { window.edulearnParticles.updateColors(accent); } }); }
initSettings();
// Auto-repair on load: Ensure particles start if enabled setTimeout(() => { if (userSettings.particlesEnabled !== false) { if (typeof initEdulearnParticles === 'function') initEdulearnParticles(); if (window.edulearnParticles) window.edulearnParticles.start(); } }, 500); });
